+                logger.error(detail);
+                await handleAgentCrash(
+                  opts.repo,
+                  opts.issueNumber,
+                  opts.resultStage,
+                  detail,
+                  `The \`${opts.resultStage}\` agent run exited with code ${initialCode}.`
