+                ...(opts.prNumber !== undefined ? { prNumber: opts.prNumber.value } : {}),
+              });
+            } catch (error) {
+              const detail = toErrorMessage(error);
+              logger.error(detail);
+              await handleAgentCrash(opts.repo, opts.issueNumber, opts.resultStage, detail);
+              process.exitCode = 1;
+            }
+          }
+        );
+      }
+    );
+  });
